import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,d as t}from"./app-d4f00f12.js";const e={},p=t(`<p>我们都知道计算机是由<strong>硬件</strong>和<strong>软件</strong>组成的。</p><ul><li>硬件中的 CPU 是计算机的核心，它承担计算机的所有任务。</li><li>操作系统是运行在硬件之上的软件，是计算机的管理者，它负责资源的管理和分配、任务的调度。</li><li>程序是运行在系统上的具有某种功能的软件，比如说浏览器，音乐播放器等。</li></ul><p>每次执行程序的时候，都会完成一定的功能，比如说浏览器帮我们打开网页，为了保证其独立性，就需要一个专门的管理和控制执行程序的数据结构——<strong>进程控制块</strong>。</p><p>进程就是一个程序在一个数据集上的一次动态执行过程。</p><ul><li>进程一般由程序、数据集、进程控制块三部分组成。 <ul><li>我们编写的程序用来描述进程要完成哪些功能以及如何完成；</li><li>数据集则是程序在执行过程中所需要使用的资源；</li><li>进程控制块用来记录进程的外部特征，描述进程的执行变化过程，系统可以利用它来控制和管理进程，它是系统感知进程存在的唯一标志</li></ul></li></ul><h2 id="进程和线程的介绍" tabindex="-1"><a class="header-anchor" href="#进程和线程的介绍" aria-hidden="true">#</a> 进程和线程的介绍</h2><h3 id="进程与线程的历史" tabindex="-1"><a class="header-anchor" href="#进程与线程的历史" aria-hidden="true">#</a> 进程与线程的历史</h3><ul><li>在早期的操作系统里，计算机只有一个核心，进程是执行程序的最小单位，任务调度采用时间片轮转的抢占式方式进行进程调度。</li><li>每个进程都有各自的一块独立的内存，保证进程彼此间的内存地址空间的隔离。</li></ul><p>随着计算机技术的发展，进程出现了很多弊端：</p><ul><li>一是进程的创建、撤销和切换的开销比较大</li><li>二是由于对称多处理机（对称多处理机（SymmetricalMulti-Processing）又叫 SMP，是指在一个计算机上汇集了一组处理器 (多 CPU)，各 CPU 之间共享内存子系统以及总线结构）的出现，可以满足多个运行单位，而多进程并行开销过大。</li></ul><p>这个时候就引入了线程的概念。</p><ul><li>线程也叫轻量级进程，它是一个基本的 CPU 执行单元，也是程序执行过程中的最小单元，由线程 ID、程序计数器、寄存器集合 和堆栈共同组成。</li><li>线程的引入减小了程序并发执行时的开销，提高了操作系统的并发性能。</li><li>线程没有自己的系统资源，只拥有在运行时必不可少的资源。</li><li>但线程可以与同属与同一进程的其他线程共享进程所拥有的其他资源。</li></ul><h3 id="进程与线程之间的关系" tabindex="-1"><a class="header-anchor" href="#进程与线程之间的关系" aria-hidden="true">#</a> 进程与线程之间的关系</h3><ul><li>线程是属于进程的，线程运行在进程空间内，同一进程所产生的线程共享同一内存空间，当进程退出时该进程所产生的线程都会被强制退出并清除。</li><li>线程可与属于同一进程的其它线程共享进程所拥有的全部资源，但是其本身基本上不拥有系统资源，只拥有一点在运行中必不可少的信息 (如程序计数器、一组寄存器和栈)。</li></ul><h3 id="守护线程与守护进程的区别" tabindex="-1"><a class="header-anchor" href="#守护线程与守护进程的区别" aria-hidden="true">#</a> 守护线程与守护进程的区别</h3><blockquote><p>强调：运行完毕，并非是终止</p></blockquote><ul><li><p>线程与进程运行完毕的区别：</p><ul><li><p>主进程运行完毕指的是主进程代码运行完毕</p></li><li><p>主线程运行完毕指的是所在的进程内的所有非守护线程运行完毕后，主线程才算运行完毕</p></li></ul></li><li><p>守护进程：主进程代码运行完毕，守护进程也就结束 <strong>(守护的是主进程)</strong></p><ul><li><p>主进程要等非守护进程都运行完毕后再回收子进程的资源（否则会产生僵尸进程）才结束</p></li><li><p>主进程等子进程是因为主进程要给子进程收尸（代用wait方法向操作系统发起回收资源信号（pid号，状态信息））</p></li></ul></li><li><p>守护线程：非守护线程代码运行完毕，守护线程也就结束 <strong>(守护的是非守护线程)</strong></p><ul><li><p>主线程在其他非守护线程运行完毕后才算结束（守护线程在此时就会被回收）</p></li><li><p>强调：主线程也是非守护线程（进程包含了线程）</p></li></ul></li></ul><blockquote><p>总结:主线程的结束意味着进程结束，进程整体的资源都会被回收，而进程必须保证非守护线程都运行完毕后才能结束</p></blockquote><ul><li>守护进程：主进程代码运行完毕，守护进程也就结束</li><li>守护线程：非守护线程运行完毕，守护线程结束</li></ul><h2 id="python-线程" tabindex="-1"><a class="header-anchor" href="#python-线程" aria-hidden="true">#</a> python 线程</h2><p>Threading 用于提供线程相关的操作，线程是应用程序中工作的最小单元。</p><h3 id="threading-模块" tabindex="-1"><a class="header-anchor" href="#threading-模块" aria-hidden="true">#</a> threading 模块</h3><p>threading 模块建立在 _thread 模块之上。thread 模块以低级、原始的方式来处理和控制线程，而 threading 模块通过对 thread 进行二次封装，提供了更方便的 api 来处理线程。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> threading
<span class="token keyword">import</span> time


<span class="token keyword">def</span> <span class="token function">worker</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token triple-quoted-string string">&quot;&quot;&quot;
    thread worker function
    :return:
    &quot;&quot;&quot;</span>
    time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;The num is  %d&quot;</span> <span class="token operator">%</span> num<span class="token punctuation">)</span>
    <span class="token keyword">return</span>


<span class="token keyword">if</span> __name__ <span class="token operator">==</span> <span class="token string">&#39;__main__&#39;</span><span class="token punctuation">:</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        t <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span>target<span class="token operator">=</span>worker<span class="token punctuation">,</span> args<span class="token operator">=</span><span class="token punctuation">(</span>i<span class="token punctuation">,</span><span class="token punctuation">)</span><span class="token punctuation">,</span> name<span class="token operator">=</span><span class="token string">&quot;t.%d&quot;</span> <span class="token operator">%</span> i<span class="token punctuation">)</span>
        t<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上述代码创建了5个&quot;前台&quot;线程，然后控制器就交给了CPU，CPU根据指定算法进行调度，分片执行指令。</p><blockquote><p>Thread参数介绍：</p></blockquote><ul><li><p>group：参数未使用，默认值为None。</p></li><li><p>target：表示调用对象，即子线程要执行的任务。</p></li><li><p>args：表示调用的位置参数元组。</p></li><li><p>kwargs：表示调用对象的字典。如kwargs = {&#39;name&#39;:Jack, &#39;age&#39;:18}。</p></li><li><p>name：子进程名称。</p></li><li><p>daemon：设置为守护线程(True)或非守护线程(默认：False)</p></li></ul><blockquote><p>Thread属性方法说明</p></blockquote><table><thead><tr><th style="text-align:center;">方法/属性</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">start()</td><td style="text-align:left;">激活线程。使用该方法启动一个子线程，线程名就是我们定义的name，想启动多线程，就必须使用此方法</td></tr><tr><td style="text-align:center;">run()</td><td style="text-align:left;">线程被cpu调度后自动执行线程对象的run方法,直接使用该方法并不启动一个新线程，就是在主线程中调用了一个普通函数而已</td></tr><tr><td style="text-align:center;">ident</td><td style="text-align:left;">获取线程的标识符。线程标识符是一个非零整数，只有在调用了start()方法之后该属性才有效，否则它只返回None。</td></tr><tr><td style="text-align:center;">name</td><td style="text-align:left;">获取或设置线程的名称</td></tr><tr><td style="text-align:center;">getName()</td><td style="text-align:left;">获取线程的名称</td></tr><tr><td style="text-align:center;">setName()</td><td style="text-align:left;">设置线程的名称</td></tr><tr><td style="text-align:center;">is_alive()</td><td style="text-align:left;">判断线程是否为激活状态</td></tr><tr><td style="text-align:center;">isAlive()</td><td style="text-align:left;">判断线程是否为激活状态</td></tr><tr><td style="text-align:center;">setDaemon()</td><td style="text-align:left;">设置为守护线程或非守护线程；默认值为False，如果设置为True，代表该进程为后台守护线程；当非守护线程(不只是主线程)终止时，该线程也随之终止；并且设置为True后，该线程不能创建子线程，设置该属性设置必须在start()之前</td></tr><tr><td style="text-align:center;">isDaemon()</td><td style="text-align:left;">判断是否为守护线程</td></tr><tr><td style="text-align:center;">join()</td><td style="text-align:left;">阻塞等待该线程执行完毕，该方法主要让主线程阻塞等待所有子线程执行完毕</td></tr></tbody></table><h3 id="线程锁threading-rlock和threading-lock" tabindex="-1"><a class="header-anchor" href="#线程锁threading-rlock和threading-lock" aria-hidden="true">#</a> 线程锁threading.RLock和threading.Lock</h3><p>由于线程之间是进行随机调度，并且每个线程可能只执行n条执行之后，CPU接着执行其他线程。为了保证数据的准确性，引入了锁的概念。所以，可能出现如下问题：</p><p>假设两个线程t1和t2都要对全局变量g_num(默认是0)进行加1运算，t1和t2都各对g_num加1000000次，g_num的最终的结果应该为2000000。</p><p>但是由于是多线程同时操作，有可能出现下面情况：</p><p>在g_num=0时，t1取得g_num=0。此时系统把t1调度为”sleeping”状态，把t2转换为”running”状态，t2也获得g_num=0<br> 然后t2对得到的值进行加1并赋给g_num，使得g_num=1<br> 然后系统又把t2调度为”sleeping”，把t1转为”running”。线程t1又把它之前得到的0加1后赋值给g_num。<br> 这样导致虽然t1和t2都对g_num加1，但结果仍然是g_num=1<br><strong>如果多个线程同时对同一个全局变量操作，会出现资源竞争问题，从而数据结果会不正确，锁的出现解决了这个问题。</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> threading

g_num <span class="token operator">=</span> <span class="token number">0</span>
lock <span class="token operator">=</span> threading<span class="token punctuation">.</span>Lock<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">#创建锁</span>


<span class="token keyword">def</span> <span class="token function">work1</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">global</span> g_num
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">:</span>
        lock<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 加锁</span>
        g_num <span class="token operator">+=</span> <span class="token number">1</span>
        lock<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 解锁</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;----in work1, g_num is %d---&quot;</span> <span class="token operator">%</span> g_num<span class="token punctuation">)</span>


<span class="token keyword">def</span> <span class="token function">work2</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">global</span> g_num
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">:</span>
        lock<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span>
        g_num <span class="token operator">+=</span> <span class="token number">1</span>
        lock<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;----in work2, g_num is %d---&quot;</span> <span class="token operator">%</span> g_num<span class="token punctuation">)</span>


<span class="token keyword">if</span> __name__ <span class="token operator">==</span> <span class="token string">&#39;__main__&#39;</span><span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;---线程创建之前g_num is %d---&quot;</span> <span class="token operator">%</span> g_num<span class="token punctuation">)</span>
    t1 <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span>target<span class="token operator">=</span>work1<span class="token punctuation">,</span> args<span class="token operator">=</span><span class="token punctuation">(</span><span class="token number">1000000</span><span class="token punctuation">,</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
    t2 <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span>target<span class="token operator">=</span>work2<span class="token punctuation">,</span> args<span class="token operator">=</span><span class="token punctuation">(</span><span class="token number">1000000</span><span class="token punctuation">,</span><span class="token punctuation">)</span><span class="token punctuation">)</span>

    t1<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>
    t2<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>

    t1<span class="token punctuation">.</span>join<span class="token punctuation">(</span><span class="token punctuation">)</span>
    t2<span class="token punctuation">.</span>join<span class="token punctuation">(</span><span class="token punctuation">)</span>

    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;2个线程对同一个全局变量操作之后的最终结果是:%s&quot;</span> <span class="token operator">%</span> g_num<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="threading-rlock和threading-lock-的区别" tabindex="-1"><a class="header-anchor" href="#threading-rlock和threading-lock-的区别" aria-hidden="true">#</a> threading.RLock和threading.Lock 的区别</h3><p>RLock允许在同一线程中被多次acquire。而Lock却不允许这种情况。</p><p>如果使用RLock，那么acquire和release必须成对出现，即调用了n次acquire，必须调用n次的release才能真正释放所占用的锁。</p><ul><li>Lock多次加锁演示</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> threading
lock <span class="token operator">=</span> threading<span class="token punctuation">.</span>Lock<span class="token punctuation">(</span><span class="token punctuation">)</span>    <span class="token comment">#Lock对象</span>
lock<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span>
lock<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment">#产生了死锁。</span>
lock<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span>
lock<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>RLock多次加锁演示</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> threading
rLock <span class="token operator">=</span> threading<span class="token punctuation">.</span>RLock<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment">#RLock对象</span>
rLock<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span>
rLock<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span>    <span class="token comment">#在同一线程内，程序不会堵塞。</span>
rLock<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span>
rLock<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="threading-event" tabindex="-1"><a class="header-anchor" href="#threading-event" aria-hidden="true">#</a> threading.Event</h3><p>通过threading.Event()可以创建一个事件管理标志，该标志（event）默认为False，event对象主要有四种方法可以调用：</p><ul><li>event.wait(timeout=None)：调用该方法的线程会被阻塞，如果设置了timeout参数，超时后，线程会停止阻塞继续执行；</li><li>event.set()：将event的标志设置为True，调用wait方法的所有线程将被唤醒；</li><li>event.clear()：将event的标志设置为False，调用wait方法的所有线程将被阻塞；</li><li>event.isSet()：判断event的标志是否为True。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> threading

<span class="token keyword">def</span> <span class="token function">do</span><span class="token punctuation">(</span>event<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;start&#39;</span><span class="token punctuation">)</span>
    event<span class="token punctuation">.</span>wait<span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;execute&#39;</span><span class="token punctuation">)</span>

event_obj <span class="token operator">=</span> threading<span class="token punctuation">.</span>Event<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    t <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span>target<span class="token operator">=</span>do<span class="token punctuation">,</span> args<span class="token operator">=</span><span class="token punctuation">(</span>event_obj<span class="token punctuation">,</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
    t<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>

event_obj<span class="token punctuation">.</span>clear<span class="token punctuation">(</span><span class="token punctuation">)</span>
inp <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token string">&#39;input:&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">if</span> inp <span class="token operator">==</span> <span class="token string">&#39;true&#39;</span><span class="token punctuation">:</span>
    event_obj<span class="token punctuation">.</span><span class="token builtin">set</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="threading-condition" tabindex="-1"><a class="header-anchor" href="#threading-condition" aria-hidden="true">#</a> threading.Condition</h3><p>Python提供的Condition对象提供了对复杂线程同步问题的支持。</p><ul><li>Condition被称为条件变量，除了提供与Lock类似的acquire和release方法外，还提供了wait和notify方法。</li></ul><h4 id="condition的处理流程如下" tabindex="-1"><a class="header-anchor" href="#condition的处理流程如下" aria-hidden="true">#</a> Condition的处理流程如下：</h4><ul><li>首先acquire一个条件变量，然后判断一些条件。</li><li>如果条件不满足则wait；</li><li>如果条件满足，进行一些处理改变条件后，通过notify方法通知其他线程，其他处于wait状态的线程接到通知后会重新判断条件。</li><li>不断的重复这一过程，从而解决复杂的同步问题。</li></ul><h4 id="condition的基本原理如下" tabindex="-1"><a class="header-anchor" href="#condition的基本原理如下" aria-hidden="true">#</a> Condition的基本原理如下：</h4><p>可以认为<strong>Condition对象</strong>维护了一个<strong>锁（Lock/RLock)<strong>和一个</strong>waiting池</strong>。线程通过acquire获得Condition对象，当调用wait方法时，线程会释放Condition内部的锁并进入blocked状态，同时在waiting池中记录这个线程。当调用notify方法时，Condition对象会从waiting池中挑选一个线程，通知其调用acquire方法尝试取到锁。</p><p>Condition对象的构造函数可以接受一个Lock/RLock对象作为参数，如果没有指定，则Condition对象会在内部自行创建一个RLock。</p><p>除了notify方法外，Condition对象还提供了notifyAll方法，可以通知waiting池中的所有线程尝试acquire内部锁。由于上述机制，<strong>处于waiting状态的线程只能通过notify方法唤醒，所以notifyAll的作用在于防止有的线程永远处于沉默状态。</strong></p><h4 id="condition的案例演示如下" tabindex="-1"><a class="header-anchor" href="#condition的案例演示如下" aria-hidden="true">#</a> Condition的案例演示如下：</h4><p>演示条件变量同步的经典问题是生产者与消费者问题：假设有一群生产者(Producer)和一群消费者（Consumer）通过一个市场来交互产品。生产者的”策略“是如果市场上剩余的产品少于1000个，那么就生产100个产品放到市场上；而消费者的”策略“是如果市场上剩余产品的数量多余100个，那么就消费3个产品。</p><p>用Condition解决生产者与消费者问题的代码如下：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># -*- coding: utf-8 -*-</span>
<span class="token triple-quoted-string string">&quot;&quot;&quot;
Created on Wed Nov 28 17:15:29 2018

@author: 18665
&quot;&quot;&quot;</span>

<span class="token keyword">import</span> threading
<span class="token keyword">import</span> time

<span class="token keyword">class</span> <span class="token class-name">Producer</span><span class="token punctuation">(</span>threading<span class="token punctuation">.</span>Thread<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token comment"># 生产者函数</span>
    <span class="token keyword">def</span> <span class="token function">run</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">global</span> count
        <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
            <span class="token keyword">if</span> con<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
                <span class="token comment"># 当count 小于等于1000 的时候进行生产</span>
                <span class="token keyword">if</span> count <span class="token operator">&gt;</span> <span class="token number">1000</span><span class="token punctuation">:</span>
                    con<span class="token punctuation">.</span>wait<span class="token punctuation">(</span><span class="token punctuation">)</span>
                <span class="token keyword">else</span><span class="token punctuation">:</span>
                    count <span class="token operator">=</span> count<span class="token operator">+</span><span class="token number">100</span>
                    msg <span class="token operator">=</span> self<span class="token punctuation">.</span>name<span class="token operator">+</span><span class="token string">&#39; produce 100, count=&#39;</span> <span class="token operator">+</span> <span class="token builtin">str</span><span class="token punctuation">(</span>count<span class="token punctuation">)</span>
                    <span class="token keyword">print</span><span class="token punctuation">(</span>msg<span class="token punctuation">)</span>
                    <span class="token comment"># 完成生成后唤醒waiting状态的线程，</span>
                    <span class="token comment"># 从waiting池中挑选一个线程，通知其调用acquire方法尝试取到锁</span>
                    con<span class="token punctuation">.</span>notify<span class="token punctuation">(</span><span class="token punctuation">)</span>
                con<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span>
                time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>

<span class="token keyword">class</span> <span class="token class-name">Consumer</span><span class="token punctuation">(</span>threading<span class="token punctuation">.</span>Thread<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token comment"># 消费者函数</span>
    <span class="token keyword">def</span> <span class="token function">run</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">global</span> count
        <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
            <span class="token comment"># 当count 大于等于100的时候进行消费</span>
            <span class="token keyword">if</span> con<span class="token punctuation">.</span>acquire<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
                <span class="token keyword">if</span> count <span class="token operator">&lt;</span> <span class="token number">100</span><span class="token punctuation">:</span>
                    con<span class="token punctuation">.</span>wait<span class="token punctuation">(</span><span class="token punctuation">)</span>

                <span class="token keyword">else</span><span class="token punctuation">:</span>
                    count <span class="token operator">=</span> count<span class="token operator">-</span><span class="token number">5</span>
                    msg <span class="token operator">=</span> self<span class="token punctuation">.</span>name<span class="token operator">+</span><span class="token string">&#39; consume 5, count=&#39;</span><span class="token operator">+</span><span class="token builtin">str</span><span class="token punctuation">(</span>count<span class="token punctuation">)</span>
                    <span class="token keyword">print</span><span class="token punctuation">(</span>msg<span class="token punctuation">)</span>
                    con<span class="token punctuation">.</span>notify<span class="token punctuation">(</span><span class="token punctuation">)</span>
                    <span class="token comment"># 完成生成后唤醒waiting状态的线程，</span>
                    <span class="token comment"># 从waiting池中挑选一个线程，通知其调用acquire方法尝试取到锁</span>
                con<span class="token punctuation">.</span>release<span class="token punctuation">(</span><span class="token punctuation">)</span>
                time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>

count <span class="token operator">=</span> <span class="token number">500</span>
con <span class="token operator">=</span> threading<span class="token punctuation">.</span>Condition<span class="token punctuation">(</span><span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        p <span class="token operator">=</span> Producer<span class="token punctuation">(</span><span class="token punctuation">)</span>
        p<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        c <span class="token operator">=</span> Consumer<span class="token punctuation">(</span><span class="token punctuation">)</span>
        c<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">if</span> __name__ <span class="token operator">==</span> <span class="token string">&#39;__main__&#39;</span><span class="token punctuation">:</span>
    test<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="queue模块" tabindex="-1"><a class="header-anchor" href="#queue模块" aria-hidden="true">#</a> queue模块</h3><p>queue.Queue 就是消息队列，可以利用它实现线程间的安全通信。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> queue

q <span class="token operator">=</span> queue<span class="token punctuation">.</span>Queue<span class="token punctuation">(</span>maxsize<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">)</span>  <span class="token comment"># 构造一个先进显出队列，maxsize指定队列长度，为0 时，表示队列长度无限制。</span>

q<span class="token punctuation">.</span>join<span class="token punctuation">(</span><span class="token punctuation">)</span>    <span class="token comment"># 等到队列为kong的时候，在执行别的操作</span>
q<span class="token punctuation">.</span>qsize<span class="token punctuation">(</span><span class="token punctuation">)</span>   <span class="token comment"># 返回队列的大小 （不可靠）</span>
q<span class="token punctuation">.</span>empty<span class="token punctuation">(</span><span class="token punctuation">)</span>   <span class="token comment"># 当队列为空的时候，返回True 否则返回False （不可靠）</span>
q<span class="token punctuation">.</span>full<span class="token punctuation">(</span><span class="token punctuation">)</span>    <span class="token comment"># 当队列满的时候，返回True，否则返回False （不可靠）</span>
q<span class="token punctuation">.</span>put<span class="token punctuation">(</span>item<span class="token punctuation">,</span> block<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span> timeout<span class="token operator">=</span><span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token comment">#  将item放入Queue尾部，item必须存在，可以参数block默认为True,表示当队列满时，会等待队列给出可用位置，为False时为非阻塞，此时如果队列已满，会引发queue.Full 异常。 可选参数timeout，表示 会阻塞设置的时间，过后，如果队列无法给出放入item的位置，则引发 queue.Full 异常</span>
q<span class="token punctuation">.</span>get<span class="token punctuation">(</span>block<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span> timeout<span class="token operator">=</span><span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token comment">#   移除并返回队列头部的一个值，可选参数block默认为True，表示获取值的时候，如果队列为空，则阻塞，为False时，不阻塞，若此时队列为空，则引发 queue.Empty异常。 可选参数timeout，表示会阻塞设置的时候，过后，如果队列为空，则引发Empty异常。</span>
q<span class="token punctuation">.</span>put_nowait<span class="token punctuation">(</span>item<span class="token punctuation">)</span> <span class="token comment">#   等效于 put(item,block=False)</span>
q<span class="token punctuation">.</span>get_nowait<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">#    等效于 get(item,block=False)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>代码如下：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> queue
<span class="token keyword">import</span> threading
<span class="token keyword">import</span> time

message <span class="token operator">=</span> queue<span class="token punctuation">.</span>Queue<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>


<span class="token keyword">def</span> <span class="token function">producer</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        message<span class="token punctuation">.</span>put<span class="token punctuation">(</span>i<span class="token punctuation">)</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;PUT&gt;&gt;&gt;%d&quot;</span> <span class="token operator">%</span> i<span class="token punctuation">)</span>


<span class="token keyword">def</span> <span class="token function">consumer</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        msg <span class="token operator">=</span> message<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token punctuation">)</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;GET&gt;&gt;&gt;%d&quot;</span> <span class="token operator">%</span> msg<span class="token punctuation">)</span>
        time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>


<span class="token keyword">if</span> __name__ <span class="token operator">==</span> <span class="token string">&#39;__main__&#39;</span><span class="token punctuation">:</span>
    t1 <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span>target<span class="token operator">=</span>producer<span class="token punctuation">)</span>
    t2 <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span>target<span class="token operator">=</span>consumer<span class="token punctuation">)</span>

    t1<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>
    t2<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="python-进程" tabindex="-1"><a class="header-anchor" href="#python-进程" aria-hidden="true">#</a> Python 进程</h2><h3 id="multiprocess模块" tabindex="-1"><a class="header-anchor" href="#multiprocess模块" aria-hidden="true">#</a> multiprocess模块</h3><p>process模块是一个创建进程的模块，借助这个模块，就可以完成进程的创建。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>语法：Process<span class="token punctuation">(</span><span class="token punctuation">[</span>group <span class="token punctuation">[</span>, target <span class="token punctuation">[</span>, name <span class="token punctuation">[</span>, args <span class="token punctuation">[</span>, kwargs<span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> multiprocessing
<span class="token keyword">import</span> time


<span class="token keyword">def</span> <span class="token function">worker</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token triple-quoted-string string">&quot;&quot;&quot;
    process worker function
    :return:
    &quot;&quot;&quot;</span>
    time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;The num is  %d&quot;</span> <span class="token operator">%</span> num<span class="token punctuation">)</span>
    <span class="token keyword">return</span>


<span class="token keyword">if</span> __name__ <span class="token operator">==</span> <span class="token string">&#39;__main__&#39;</span><span class="token punctuation">:</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        t <span class="token operator">=</span> multiprocessing<span class="token punctuation">.</span>Process<span class="token punctuation">(</span>target<span class="token operator">=</span>worker<span class="token punctuation">,</span> args<span class="token operator">=</span><span class="token punctuation">(</span>i<span class="token punctuation">,</span><span class="token punctuation">)</span><span class="token punctuation">,</span> name<span class="token operator">=</span><span class="token string">&quot;t.%d&quot;</span> <span class="token operator">%</span> i<span class="token punctuation">)</span>
        t<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>Process参数介绍：</p></blockquote><ul><li><p>group：参数未使用，默认值为None。</p></li><li><p>target：表示调用对象，即子进程要执行的任务。</p></li><li><p>args：表示调用的位置参数元组。</p></li><li><p>kwargs：表示调用对象的字典。如kwargs = {&#39;name&#39;:Jack, &#39;age&#39;:18}。</p></li><li><p>name：子进程名称。</p></li><li><p>daemon：设置为守护进程(True)或非守护进程(默认：False)</p></li></ul><blockquote><p>Process属性方法介绍</p></blockquote><table><thead><tr><th style="text-align:center;">方法/属性</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">start()</td><td style="text-align:left;">启动进程，调用进程中的run()方法。</td></tr><tr><td style="text-align:center;">run()</td><td style="text-align:left;">进程启动时运行的方法，正是它去调用target指定的函数，我们自定义类的类中一定要实现该方法 。</td></tr><tr><td style="text-align:center;">terminate()</td><td style="text-align:left;">强制终止进程，不会进行任何清理操作。如果该进程终止前，创建了子进程，那么该子进程在其强制结束后变为僵尸进程；如果该进程还保存了一个锁那么也将不会被释放，进而导致死锁。使用时，要注意。</td></tr><tr><td style="text-align:center;">is_alive()</td><td style="text-align:left;">判断某进程是否存活，存活返回True，否则False。</td></tr><tr><td style="text-align:center;">join([timeout])</td><td style="text-align:left;">主线程等待子线程终止。timeout为可选择超时时间；需要强调的是，p.join只能join住start开启的进程，而不能join住run开启的进程 。</td></tr><tr><td style="text-align:center;">daemon</td><td style="text-align:left;">默认值为False，如果设置为True，代表该进程为后台守护进程；当该进程的父进程终止时，该进程也随之终止；并且设置为True后，该进程不能创建子进程，设置该属性必须在start()之前</td></tr><tr><td style="text-align:center;">name</td><td style="text-align:left;">进程名称。</td></tr><tr><td style="text-align:center;">pid</td><td style="text-align:left;">进程pid</td></tr><tr><td style="text-align:center;">exitcode</td><td style="text-align:left;">进程运行时为None，如果为-N，表示被信号N结束了。</td></tr><tr><td style="text-align:center;">authkey</td><td style="text-align:left;">进程身份验证，默认是由os.urandom()随机生成32字符的字符串。这个键的用途是设计涉及网络连接的底层进程间的通信提供安全性，这类连接只有在具有相同身份验证才能成功。</td></tr></tbody></table><blockquote><p>注意:</p></blockquote><ul><li><strong>在进程python的设计里面只有主进程可以接收input()的输入，子进程没有输入模式，运行直接报错</strong></li><li><strong>更坑的是进程池，表面上不会出错，但是input()函数一旦进入无法退出，一直在接收输入的数据</strong></li></ul><h3 id="消息队列multiprocess-queue" tabindex="-1"><a class="header-anchor" href="#消息队列multiprocess-queue" aria-hidden="true">#</a> 消息队列multiprocess.Queue</h3><p>可以使用multiprocessing模块的Queue实现多进程之间的数据传递，Queue本身是一个消息列队程序</p><blockquote><p>Queue属性方法说明</p></blockquote><table><thead><tr><th style="text-align:center;">方法/属性</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">get( [ block [ ,timeout ] ] )</td><td style="text-align:left;">返回q中的一个元素。如果q为空，此方法将阻塞，直到队列中有项目可用为止。block用于控制阻塞行为，默认为True. 如果设置为False，将引发Queue.Empty异常（定义在Queue模块中）。timeout是可选超时时间，用在阻塞模式中。如果在制定的时间间隔内没有项目变为可用，将引发Queue.Empty异常。</td></tr><tr><td style="text-align:center;">get_nowait( )</td><td style="text-align:left;">同q.get(False)方法。</td></tr><tr><td style="text-align:center;">put(item [, block [,timeout ] ] )</td><td style="text-align:left;">将item放入队列。如果队列已满，此方法将阻塞至有空间可用为止。block控制阻塞行为，默认为True。如果设置为False，将引发Queue.Empty异常（定义在Queue库模块中）。timeout指定在阻塞模式中等待可用空间的时间长短。超时后将引发Queue.Full异常。</td></tr><tr><td style="text-align:center;">q.qsize()</td><td style="text-align:left;">返回队列中目前项目的正确数量。此函数的结果并不可靠，因为在返回结果和在稍后程序中使用结果之间，队列中可能添加或删除了项目。在某些系统上，此方法可能引发NotImplementedError异常。</td></tr><tr><td style="text-align:center;">q.empty()</td><td style="text-align:left;">如果调用此方法时 q为空，返回True。如果其他进程或线程正在往队列中添加项目，结果是不可靠的。也就是说，在返回和使用结果之间，队列中可能已经加入新的项目。</td></tr><tr><td style="text-align:center;">q.full()</td><td style="text-align:left;">如果q已满，返回为True. 由于线程的存在，结果也可能是不可靠的（参考q.empty（）方法）。。</td></tr><tr><td style="text-align:center;">其他方法(了解)</td><td style="text-align:left;"></td></tr><tr><td style="text-align:center;">q.close()</td><td style="text-align:left;">关闭队列，防止队列中加入更多数据。调用此方法时，后台线程将继续写入那些已入队列但尚未写入的数据，但将在此方法完成时马上关闭。如果q被垃圾收集，将自动调用此方法。关闭队列不会在队列使用者中生成任何类型的数据结束信号或异常。例如，如果某个使用者正被阻塞在get（）操作上，关闭生产者中的队列不会导致get（）方法返回错误。</td></tr><tr><td style="text-align:center;">q.cancel_join_thread()</td><td style="text-align:left;">不会再进程退出时自动连接后台线程。这可以防止join_thread()方法阻塞。</td></tr><tr><td style="text-align:center;">q.join_thread()</td><td style="text-align:left;">连接队列的后台线程。此方法用于在调用q.close()方法后，等待所有队列项被消耗。默认情况下，此方法由不是q的原始创建者的所有进程调用。调用q.cancel_join_thread()方法可以禁止这种行为。</td></tr></tbody></table><h3 id="进程池" tabindex="-1"><a class="header-anchor" href="#进程池" aria-hidden="true">#</a> 进程池</h3><p>为什么要有进程池?进程池的概念。</p><p>在程序实际处理问题过程中，忙时会有成千上万的任务需要被执行，闲时可能只有零星任务。那么在成千上万个任务需要被执行的时候，我们就需要去创建成千上万个进程么？首先，创建进程需要消耗时间，销毁进程也需要消耗时间。第二即便开启了成千上万的进程，操作系统也不能让他们同时执行，这样反而会影响程序的效率。因此我们不能无限制的根据任务开启或者结束进程。那么我们要怎么做呢？</p><p>在这里，要给大家介绍一个进程池的概念，定义一个池子，在里面放上固定数量的进程，有需求来了，就拿一个池中的进程来处理任务，等到处理完毕，进程并不关闭，而是将进程再放回进程池中继续等待任务。如果有很多任务需要执行，池中的进程数量不够，任务就要等待之前的进程执行任务完毕归来，拿到空闲进程才能继续执行。也就是说，池中进程的数量是固定的，那么同一时间最多有固定数量的进程在运行。这样不会增加操作系统的调度难度，还节省了开闭进程的时间，也一定程度上能够实现并发效果。</p><h4 id="multiprocess-pool模块" tabindex="-1"><a class="header-anchor" href="#multiprocess-pool模块" aria-hidden="true">#</a> multiprocess.Pool模块</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>语法：Pool<span class="token punctuation">(</span><span class="token punctuation">[</span>numprocess  <span class="token punctuation">[</span>,initializer <span class="token punctuation">[</span>, initargs<span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p>Pool参数介绍</p></blockquote><ul><li><p>numprocess:要创建的进程数，如果省略，将默认使用cpu_count()的值</p></li><li><p>initializer：是每个工作进程启动时要执行的可调用对象，默认为None</p></li><li><p>initargs：是要传给initializer（可迭代）的参数组</p></li></ul><blockquote><p>Pool主要方法介绍</p></blockquote><table><thead><tr><th style="text-align:center;">方法/属性</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">apply(func [, args [, kwargs]])</td><td style="text-align:left;">在一个池工作进程中执行func(*args,**kwargs),然后返回结果。&#39;需要强调的是：此操作并不会在所有池工作进程中并执行func函数。如果要通过不同参数并发地执行func函数，必须从不同线程调用apply()函数或者使用p.apply_async()</td></tr><tr><td style="text-align:center;">apply_async(func [, args [, kwargs]])</td><td style="text-align:left;">在一个池工作进程中执行func(*args,**kwargs),然后返回结果。此方法的结果是AsyncResult类的实例，callback是可调用对象，接收输入参数。当func的结果变为可用时，将理解传递给callback。callback禁止执行任何阻塞操作，否则将接收其他异步操作中的结果。</td></tr><tr><td style="text-align:center;">close()</td><td style="text-align:left;">关闭进程池，防止进一步操作。如果所有操作持续挂起，它们将在工作进程终止前完成</td></tr><tr><td style="text-align:center;">terminate()</td><td style="text-align:left;">不管任务是否完成，立即停止工作进程。在对pool对象进程垃圾回收的时候，会立即调用terminate()</td></tr><tr><td style="text-align:center;">jion()</td><td style="text-align:left;">等待所有工作进程退出。此方法只能在close（）或teminate()之后调用</td></tr><tr><td style="text-align:center;">其他方法(了解）</td><td style="text-align:left;">方法apply_async()和map_async（）的返回值是AsyncResul的实例obj。实例具有以下方法</td></tr><tr><td style="text-align:center;">obj.get()</td><td style="text-align:left;">返回结果，如果有必要则等待结果到达。timeout是可选的。如果在指定时间内还没有到达，将引发一场。如果远程操作中引发了异常，它将在调用此方法时再次被引发。</td></tr><tr><td style="text-align:center;">obj.ready()</td><td style="text-align:left;">如果调用完成，返回True</td></tr><tr><td style="text-align:center;">obj.successful()</td><td style="text-align:left;">如果调用完成且没有引发异常，返回True，如果在结果就绪之前调用此方法，引发异常</td></tr><tr><td style="text-align:center;">obj.wait([timeout])</td><td style="text-align:left;">等待结果变为可用。</td></tr><tr><td style="text-align:center;">obj.terminate()</td><td style="text-align:left;">立即终止所有工作进程，同时不执行任何清理或结束任何挂起工作。如果p被垃圾回收，将自动调用此函数</td></tr></tbody></table><h4 id="进程池中的queue" tabindex="-1"><a class="header-anchor" href="#进程池中的queue" aria-hidden="true">#</a> 进程池中的Queue</h4><p>如果要使用Pool创建进程，就需要使用<code>multiprocessing.Manager()</code>中的<code>Queue()</code>，而不是<code>multiprocessing.Queue()</code></p><h2 id="python-协程" tabindex="-1"><a class="header-anchor" href="#python-协程" aria-hidden="true">#</a> Python 协程</h2><p>协程，又称微线程，纤程。英文名Coroutine。协程是python个中另外一种实现多任务的方式，只不过比线程更小占用更小执行单元（理解为需要的资源）。 为啥说它是一个执行单元，因为它自带CPU上下文。这样只要在合适的时机， 我们可以把一个协程 切换到另一个协程。 只要这个过程中保存或恢复 CPU上下文那么程序还是可以运行的。</p><p>通俗的理解：<strong>在一个线程中的某个函数，可以在任何地方保存当前函数的一些临时变量等信息，然后切换到另外一个函数中执行，注意不是通过调用函数的方式做到的，并且切换的次数以及什么时候再切换到原来的函数都由开发者自己确定</strong></p><h3 id="协程-vs-线程" tabindex="-1"><a class="header-anchor" href="#协程-vs-线程" aria-hidden="true">#</a> 协程 VS 线程</h3><p>在实现多任务时, 线程切换从系统层面远不止保存和恢复 CPU上下文这么简单。 操作系统为了程序运行的高效性每个线程都有自己缓存Cache等等数据，操作系统还会帮你做这些数据的恢复操作。 所以线程的切换非常耗性能。但是协程的切换只是单纯的操作CPU的上下文，所以一秒钟切换个上百万次系统都抗的住。</p><h3 id="实现方式" tabindex="-1"><a class="header-anchor" href="#实现方式" aria-hidden="true">#</a> 实现方式</h3><h4 id="yield" tabindex="-1"><a class="header-anchor" href="#yield" aria-hidden="true">#</a> yield</h4><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> time

<span class="token keyword">def</span> <span class="token function">work1</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;----work1---&quot;</span><span class="token punctuation">)</span>
        <span class="token keyword">yield</span>
        time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">0.5</span><span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">work2</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;----work2---&quot;</span><span class="token punctuation">)</span>
        <span class="token keyword">yield</span>
        time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">0.5</span><span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    w1 <span class="token operator">=</span> work1<span class="token punctuation">(</span><span class="token punctuation">)</span>
    w2 <span class="token operator">=</span> work2<span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
        <span class="token builtin">next</span><span class="token punctuation">(</span>w1<span class="token punctuation">)</span>
        <span class="token builtin">next</span><span class="token punctuation">(</span>w2<span class="token punctuation">)</span>

<span class="token keyword">if</span> __name__ <span class="token operator">==</span> <span class="token string">&quot;__main__&quot;</span><span class="token punctuation">:</span>
    main<span class="token punctuation">(</span><span class="token punctuation">)</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="greenlet" tabindex="-1"><a class="header-anchor" href="#greenlet" aria-hidden="true">#</a> greenlet</h4><p>为了更好使用协程来完成多任务，python中的greenlet模块对其封装，从而使得切换任务变的更加简单</p><p><strong>安装方式</strong><br> 使用如下命令安装greenlet模块:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> pip3 <span class="token function">install</span> greenlet
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment">#coding=utf-8</span>

<span class="token keyword">from</span> greenlet <span class="token keyword">import</span> greenlet
<span class="token keyword">import</span> time

<span class="token keyword">def</span> <span class="token function">test1</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span> <span class="token string">&quot;---A--&quot;</span>
        gr2<span class="token punctuation">.</span>switch<span class="token punctuation">(</span><span class="token punctuation">)</span>
        time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">0.5</span><span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">test2</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span> <span class="token string">&quot;---B--&quot;</span>
        gr1<span class="token punctuation">.</span>switch<span class="token punctuation">(</span><span class="token punctuation">)</span>
        time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span><span class="token number">0.5</span><span class="token punctuation">)</span>

gr1 <span class="token operator">=</span> greenlet<span class="token punctuation">(</span>test1<span class="token punctuation">)</span>
gr2 <span class="token operator">=</span> greenlet<span class="token punctuation">(</span>test2<span class="token punctuation">)</span>

<span class="token comment">#切换到gr1中运行</span>
gr1<span class="token punctuation">.</span>switch<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="gevent" tabindex="-1"><a class="header-anchor" href="#gevent" aria-hidden="true">#</a> gevent</h4><p>greenlet已经实现了协程，但是这个还的人工切换，是不是觉得太麻烦了，不要捉急，python还有一个比greenlet更强大的并且能够自动切换任务的模块gevent</p><p>其原理是当一个greenlet遇到IO(指的是input output 输入输出，比如网络、文件操作等)操作时，比如访问网络，就自动切换到其他的greenlet，等到IO操作完成，再在适当的时候切换回来继续执行。</p><p>由于IO操作非常耗时，经常使程序处于等待状态，有了gevent为我们自动切换协程，就保证总有greenlet在运行，而不是等待IO。</p><p><strong>安装方式</strong><br> 使用如下命令安装gevent模块:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pip3 <span class="token function">install</span> gevent
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在gevent中不能直接使用time.sleep类似的方法，要么使用gevent.sleep，要么利用gevent.monkey打补丁</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> gevent <span class="token keyword">import</span> monkey
<span class="token keyword">import</span> gevent
<span class="token keyword">import</span> random
<span class="token keyword">import</span> time

<span class="token keyword">def</span> <span class="token function">coroutine_work</span><span class="token punctuation">(</span>coroutine_name<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span>coroutine_name<span class="token punctuation">,</span> i<span class="token punctuation">)</span>
        time<span class="token punctuation">.</span>sleep<span class="token punctuation">(</span>random<span class="token punctuation">.</span>random<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>

gevent<span class="token punctuation">.</span>joinall<span class="token punctuation">(</span><span class="token punctuation">[</span>
        gevent<span class="token punctuation">.</span>spawn<span class="token punctuation">(</span>coroutine_work<span class="token punctuation">,</span> <span class="token string">&quot;work1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        gevent<span class="token punctuation">.</span>spawn<span class="token punctuation">(</span>coroutine_work<span class="token punctuation">,</span> <span class="token string">&quot;work2&quot;</span><span class="token punctuation">)</span>
<span class="token punctuation">]</span><span class="token punctuation">)</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="进程和线程信息" tabindex="-1"><a class="header-anchor" href="#进程和线程信息" aria-hidden="true">#</a> 进程和线程信息</h2><p>想要获取线程和进程相关信息，代码如下：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># -*- coding: utf-8 -*-</span>
<span class="token triple-quoted-string string">&quot;&quot;&quot;
获得线程, 进程 ID,NAME
总结:

&quot;&quot;&quot;</span>
<span class="token keyword">import</span> threading
<span class="token keyword">import</span> psutil
<span class="token keyword">import</span> os
<span class="token keyword">import</span> datetime

<span class="token comment"># 1 获取线程ID,NAME</span>
t <span class="token operator">=</span> threading<span class="token punctuation">.</span>currentThread<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token comment"># 线程ID</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Thread id : %d&#39;</span> <span class="token operator">%</span> t<span class="token punctuation">.</span>ident<span class="token punctuation">)</span>
<span class="token comment"># 线程NAME</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Thread name : %s&#39;</span> <span class="token operator">%</span> t<span class="token punctuation">.</span>getName<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>

<span class="token comment"># 2 获取线程ID,NAME</span>
pid <span class="token operator">=</span> os<span class="token punctuation">.</span>getpid<span class="token punctuation">(</span><span class="token punctuation">)</span>
p <span class="token operator">=</span> psutil<span class="token punctuation">.</span>Process<span class="token punctuation">(</span>pid<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;----------------&#39;</span><span class="token punctuation">)</span>
<span class="token comment"># 进程ID</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Process id : %d&#39;</span> <span class="token operator">%</span> pid<span class="token punctuation">)</span>
<span class="token comment"># 进程NAME</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Process name : %s&#39;</span> <span class="token operator">%</span> p<span class="token punctuation">.</span>name<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 获取进程bin路径</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Process bin  path : %s&#39;</span> <span class="token operator">%</span> p<span class="token punctuation">.</span>exe<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 获取pid对应的路径</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Process path : %s&#39;</span> <span class="token operator">%</span> p<span class="token punctuation">.</span>cwd<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 进程状态</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Process status : %s&#39;</span> <span class="token operator">%</span> p<span class="token punctuation">.</span>status<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 进程运行时间</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Process creation time : %s&#39;</span> <span class="token operator">%</span> datetime<span class="token punctuation">.</span>datetime<span class="token punctuation">.</span>fromtimestamp<span class="token punctuation">(</span>p<span class="token punctuation">.</span>create_time<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>strftime<span class="token punctuation">(</span><span class="token string">&quot;%Y-%m-%d %H:%M:%S&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># CPU使用情况</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>p<span class="token punctuation">.</span>cpu_times<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 内存使用情况</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Memory usage : %s%%&#39;</span> <span class="token operator">%</span> p<span class="token punctuation">.</span>memory_percent<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 硬盘读取信息</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>p<span class="token punctuation">.</span>io_counters<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 打开进程socket的namedutples列表</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>p<span class="token punctuation">.</span>connections<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 此进程的线程数</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Process number of threads : %s&#39;</span> <span class="token operator">%</span> p<span class="token punctuation">.</span>num_threads<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,116),i=[p];function o(l,c){return s(),a("div",null,i)}const d=n(e,[["render",o],["__file","多任务机制.html.vue"]]);export{d as default};
